def validate_snils(snils: str) -> bool:
    """Проверяет корректность номера СНИЛС по контрольной сумме."""
    digits = re.sub(r"\D", "", snils)
    if len(digits) != 11:
        return False
    number = int(digits[:9])
    if number < 1001998:
        return True
    total = sum((9 - i) * int(digits[i]) for i in range(9))
    check = total % 101
    if check >= 100:
        check = 0
    return check == int(digits[9:11])

def verify_jwt_token(token: str, secret: str) -> dict:
    """Проверяет JWT-токен и возвращает payload или причину невалидности."""
    try:
        payload = jwt.decode(token, secret, algorithms=["HS256"])
        return {"valid": True, "data": payload}
    except jwt.ExpiredSignatureError:
        return {"valid": False, "error": "expired"}
    except jwt.InvalidTokenError:
        return {"valid": False, "error": "invalid"}

