def format_bytes(size: int) -> str:
    """Форматирует количество байт в читаемую строку с суффиксом KB, MB, GB или TB."""
    for unit in ("B", "KB", "MB", "GB", "TB"):
        if abs(size) < 1024:
            return f"{size:.1f} {unit}"
        size /= 1024
    return f"{size:.1f} PB"

