def upload_file_multipart(url: str, file_path: str, field_name: str = "file",
                          extra_fields: dict | None = None) -> dict:
    """Загружает файл на сервер через multipart/form-data POST-запрос."""
    with open(file_path, "rb") as f:
        files = {field_name: (pathlib.Path(file_path).name, f)}
        data = extra_fields or {}
        resp = requests.post(url, files=files, data=data, timeout=60)
    resp.raise_for_status()
    return resp.json()

