def validate_url(url: str) -> bool:
    """Проверяет корректность URL, требуя наличие схемы http/https и хоста."""
    try:
        parsed = urllib.parse.urlparse(url)
        return parsed.scheme in ("http", "https") and bool(parsed.netloc)
    except Exception:
        return False

def retry_request(url: str, method: str = "GET", max_retries: int = 3,
                  backoff: float = 1.0, **kwargs) -> requests.Response:
    """Повторяет HTTP-запрос с экспоненциальной задержкой при ошибках соединения."""
    for attempt in range(max_retries):
        try:
            resp = requests.request(method, url, timeout=10, **kwargs)
            resp.raise_for_status()
            return resp
        except requests.RequestException:
            if attempt == max_retries - 1:
                raise
            time.sleep(backoff * (2 ** attempt))

